// Simulate realistic heart rate with variability
let hr = ctx.getVar('heartRate');
const baseHR = ctx.getVar('baseHeartRate');
const variability = ctx.getVar('hrVariability');

// Add heart rate variability (HRV)
const delta = Math.floor((Math.random() - 0.5) * variability * 2);
hr = Math.max(40, Math.min(220, baseHR + delta));
ctx.setVar('heartRate', hr);

// Increment energy expended (~1 kJ per minute at rest)
let energy = ctx.getVar('energyExpended');
energy = Math.min(65535, energy + 1);
ctx.setVar('energyExpended', energy);

// Build BLE Heart Rate Measurement packet
// Flags: bit 3 = energy present, bit 4 = RR present
const w = writer();
w.uint8(0x18);      // flags: energy + RR interval
w.uint8(hr);        // heart rate (uint8)
w.uint16LE(energy); // energy expended (kJ)

// RR interval in 1/1024 seconds
const rrInterval = Math.floor((60 / hr) * 1024);
w.uint16LE(rrInterval);

ctx.log(`HR=${hr} bpm, Energy=${energy} kJ`);
return w.build();

// Parse Heart Rate Control Point commands
// Command 0x01 = Reset Energy Expended

if (input.length === 0) {
  ctx.log('Control Point: empty command');
  return null;
}

const cmd = reader(input).uint8();

if (cmd === 0x01) {
  ctx.setVar('energyExpended', 0);
  ctx.log('Control Point: Energy Expended reset to 0');
} else {
  ctx.log(`Control Point: Unknown command 0x${cmd.toString(16)}`);
}

return null;

// Return Body Sensor Location
// 0=Other, 1=Chest, 2=Wrist, 3=Finger, 4=Hand, 5=Ear Lobe, 6=Foot

const location = ctx.getVar('sensorLocation');
ctx.log(`Body Sensor Location: ${location}`);

return writer().uint8(location).build();

// Return current battery level (0-100%)

const level = ctx.getVar('batteryLevel');
ctx.log(`Battery Level: ${level}%`);

return writer().uint8(level).build();

// Reset all variables to default values
ctx.setVar('heartRate', 72);
ctx.setVar('baseHeartRate', 72);
ctx.setVar('hrVariability', 5);
ctx.setVar('energyExpended', 0);
ctx.setVar('batteryLevel', 85);

ctx.log('All variables reset to defaults');

// Return current HR measurement
const w = writer();
w.uint8(0x18);
w.uint8(72);
w.uint16LE(0);
w.uint16LE(Math.floor((60 / 72) * 1024));
return w.build();
